import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";

function Courses() {
  const user = useSelector((state) => state.auth.user);
  const [courses, setCourses] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [tests, setTests] = useState([]);
  const [files, setFiles] = useState([]);
  const [studentUploads, setStudentUploads] = useState([]);
  const [uploadFiles, setUploadFiles] = useState({});

  useEffect(() => {
    if (user?.role === "student" && user?.id && user?.classId) {
      fetch(`http://localhost:3001/enrollments?userId=${user.id}`)
        .then((res) => res.json())
        .then((data) => {
          setEnrollments(Array.isArray(data) ? data : []);
          fetch(`http://localhost:3001/courses?classId=${user.classId}`)
            .then((res) => res.json())
            .then((courseData) => {
              setCourses(Array.isArray(courseData) ? courseData : []);
              if (courseData.length > 0) {
                const courseIds = courseData.map((c) => c.id);
                fetch(`http://localhost:3001/files?courseId=${courseIds.join("&courseId=")}`)
                  .then((res) => res.json())
                  .then((fileData) => setFiles(Array.isArray(fileData) ? fileData : []))
                  .catch((error) => toast.error("Ошибка загрузки файлов"));
                fetch(`http://localhost:3001/student_uploads?userId=${user.id}&courseId=${courseIds.join("&courseId=")}`)
                  .then((res) => res.json())
                  .then((uploadData) => setStudentUploads(Array.isArray(uploadData) ? uploadData : []))
                  .catch((error) => toast.error("Ошибка загрузки отправленных файлов"));
              }
            })
            .catch((error) => {
              toast.error("Ошибка загрузки курсов");
              setCourses([]);
            });
          const courseIds = data.map((e) => e.courseId);
          if (courseIds.length > 0) {
            fetch(`http://localhost:3001/tests?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((testData) => setTests(Array.isArray(testData) ? testData : []))
              .catch((error) => toast.error("Ошибка загрузки тестов"));
          } else {
            setTests([]);
          }
        })
        .catch((error) => {
          toast.error("Ошибка загрузки записей");
          setEnrollments([]);
        });
    } else if (user?.role === "teacher" && user?.id) {
      fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((data) => {
          setCourses(Array.isArray(data) ? data : []);
          if (data.length > 0) {
            const courseIds = data.map((c) => c.id);
            fetch(`http://localhost:3001/files?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((fileData) => setFiles(Array.isArray(fileData) ? fileData : []))
              .catch((error) => toast.error("Ошибка загрузки файлов"));
            fetch(`http://localhost:3001/student_uploads?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((uploadData) => setStudentUploads(Array.isArray(uploadData) ? uploadData : []))
              .catch((error) => toast.error("Ошибка загрузки файлов студентов"));
          }
        })
        .catch((error) => {
          toast.error("Ошибка загрузки курсов");
        });
    }
  }, [user]);

  const handleFileChange = (courseId, e) => {
    setUploadFiles((prev) => ({ ...prev, [courseId]: e.target.files[0] }));
  };

  const handleFileUpload = async (courseId, e) => {
    e.preventDefault();
    const file = uploadFiles[courseId];
    if (!file) {
      toast.error("Выберите файл для загрузки!");
      return;
    }
    const formData = new FormData();
    formData.append("file", file);
    try {
      const response = await fetch("http://localhost:3002/upload", {
        method: "POST",
        body: formData,
      });
      if (response.ok) {
        const { filename, originalName } = await response.json();
        const uploadData = {
          courseId: parseInt(courseId),
          userId: user.id,
          filename,
          originalName,
          path: `uploads/${filename}`,
          createdAt: new Date().toISOString(),
        };
        const uploadResponse = await fetch("http://localhost:3001/student_uploads", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(uploadData),
        });
        if (uploadResponse.ok) {
          toast.success("Файл успешно загружен!");
          setUploadFiles((prev) => ({ ...prev, [courseId]: null }));
          const updatedUploads = await fetch(`http://localhost:3001/student_uploads?userId=${user.id}&courseId=${courseId}`)
            .then((res) => res.json());
          setStudentUploads(updatedUploads);
        }
      }
    } catch (error) {
      toast.error("Ошибка при загрузке файла");
    }
  };

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Курсы</h1>
      <div className="card shadow">
        <div className="card-body">
          <h2 className="card-title">{user.role === "student" ? "Курсы вашего класса" : "Ваши преподаваемые курсы"}</h2>
          {courses.length === 0 ? (
            <p>Нет доступных курсов</p>
          ) : (
            <ul className="list-group">
              {courses.map((course) => (
                <li key={course.id} className="list-group-item">
                  <strong>{course.name}</strong>
                  {user.role === "student" && (
                    <div>
                      <p>Статус: {enrollments.some((e) => e.courseId === course.id) ? "Записан" : "Не записан"}</p>
                      <h6>Тесты:</h6>
                      {tests.filter((t) => t.courseId === course.id).length === 0 ? (
                        <p>Тестов нет</p>
                      ) : (
                        <ul>
                          {tests.filter((t) => t.courseId === course.id).map((test) => (
                            <li key={test.id}>
                              <Link to={`/take-test/${test.id}`}>{test.title}</Link>
                            </li>
                          ))}
                        </ul>
                      )}
                      <h6>Файлы от учителя:</h6>
                      {files.filter((f) => f.courseId === course.id).length === 0 ? (
                        <p>Файлов нет</p>
                      ) : (
                        <ul>
                          {files.filter((f) => f.courseId === course.id).map((file) => (
                            <li key={file.id}>
                              <a href={`http://localhost:3002/download/${file.filename}`} download={file.originalName}>
                                {file.originalName}
                              </a>
                            </li>
                          ))}
                        </ul>
                      )}
                      {enrollments.some((e) => e.courseId === course.id) && (
                        <>
                          <h6>Загрузить файл:</h6>
                          <form onSubmit={(e) => handleFileUpload(course.id, e)}>
                            <input type="file" onChange={(e) => handleFileChange(course.id, e)} />
                            <button type="submit" className="btn btn-primary btn-sm">Загрузить</button>
                          </form>
                          <h6>Ваши загруженные файлы:</h6>
                          {studentUploads.filter((u) => u.courseId === course.id).length === 0 ? (
                            <p>Вы еще не загрузили файлы</p>
                          ) : (
                            <ul>
                              {studentUploads.filter((u) => u.courseId === course.id).map((upload) => (
                                <li key={upload.id}>
                                  <a href={`http://localhost:3002/download/${upload.filename}`} download={upload.originalName}>
                                    {upload.originalName}
                                  </a>
                                </li>
                              ))}
                            </ul>
                          )}
                        </>
                      )}
                    </div>
                  )}
                  {user.role === "teacher" && (
                    <div>
                      <Link to={`/edit-course/${course.id}`} className="btn btn-secondary btn-sm me-2">Редактировать</Link>
                      <Link to="/add-test" className="btn btn-primary btn-sm me-2">Добавить тест</Link>
                      <h6>Ваши файлы:</h6>
                      {files.filter((f) => f.courseId === course.id).length === 0 ? (
                        <p>Файлов нет</p>
                      ) : (
                        <ul>
                          {files.filter((f) => f.courseId === course.id).map((file) => (
                            <li key={file.id}>
                              <a href={`http://localhost:3002/download/${file.filename}`} download={file.originalName}>
                                {file.originalName}
                              </a>
                            </li>
                          ))}
                        </ul>
                      )}
                      <h6>Файлы студентов:</h6>
                      {studentUploads.filter((u) => u.courseId === course.id).length === 0 ? (
                        <p>Студенты еще не загрузили файлы</p>
                      ) : (
                        <ul>
                          {studentUploads.filter((u) => u.courseId === course.id).map((upload) => (
                            <li key={upload.id}>
                              <a href={`http://localhost:3002/download/${upload.filename}`} download={upload.originalName}>
                                {upload.originalName} (Студент ID: {upload.userId})
                              </a>
                            </li>
                          ))}
                        </ul>
                      )}
                    </div>
                  )}
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

export default Courses;
